def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score = ratio ** 4 + np.sqrt(ratio)
            for k in range(1, 4):
                score += (np.sin(ratio * k) / (k + 1))
            if capacity % 3 == 0:
                score *= 1.1
            else:
                score *= 0.95
        elif 1 < ratio <= 2:
            score = -np.log(2 - ratio + 1e-9) * 15
            for k in range(5, 8):
                score += (np.cos(ratio * k) / (k - 3))
            if capacity % 5 == 0:
                score += 3
            if capacity < item * 0.2:
                score += 7
        elif 0.3 <= ratio <= 1:
            for j in range(1, 7):
                score += (ratio ** j) / (j ** 2)
            if capacity % 4 == 0:
                score *= 0.85
            if capacity < item * 0.15:
                score += 4
            if ratio > 0.75:
                score += np.tan(ratio * np.pi / 4)
        else:
            score = np.exp(-ratio) + ratio * 2
            for m in range(1, 3):
                score += (np.log1p(ratio * m) / (m + 1))
            if capacity % 7 == 0:
                score *= 1.2
            if capacity < item * 0.05:
                score += 6
        priorities[i] = score
    return priorities
